16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.ObjectMapper;
19	import jakarta.inject.Singleton;
20	import java.io.IOException;
21	import java.nio.file.Files;
22	import java.nio.file.Path;
23	import java.nio.file.Paths;
24	import java.time.Instant;
25	import java.util.ArrayList;
26	import java.util.Collections;
27	import java.util.List;
28	
29	/**
30	 * Persists {@link EvalRunSnapshot}s to a JSON-lines file under the user's home so eval quality can be
31	 * tracked and compared across runs. Append-on-save, newest-first on read, and capped so the file
32	 * stays small. Single-user local tool, so a coarse lock is enough for correctness.
33	 */
34	@Singleton
35	public class EvalRunStore {
36	
37	    /** Keep the history bounded; on overflow the oldest runs are dropped. */
38	    static final int MAX_RUNS = 200;
39	
40	    private static final ObjectMapper MAPPER = new ObjectMapper();
41	    private final Object lock = new Object();
42	
43	    private Path historyFile() {
44	        return Paths.get(System.getProperty("user.home"), ".agybrainviz", "eval-runs.jsonl");
45	    }
46	
47	    /** Records a snapshot of the given report (server-stamped) and returns it. */
48	    public EvalRunSnapshot save(EvalReport report) throws IOException {
49	        EvalRunSnapshot snapshot = snapshotOf(report, Instant.now().toString());
50	        synchronized (lock) {
51	            List<String> lines = new ArrayList<>(readLines());
52	            lines.add(MAPPER.writeValueAsString(snapshot));
53	            if (lines.size() > MAX_RUNS) {
54	                lines = new ArrayList<>(lines.subList(lines.size() - MAX_RUNS, lines.size()));
55	            }
56	            Path file = historyFile();
57	            Files.createDirectories(file.getParent());
58	            Files.write(file, lines);
59	        }
60	        return snapshot;
61	    }
62	
63	    /** All saved runs for a flavor, newest first. */
64	    public List<EvalRunSnapshot> list(String flavor) throws IOException {
65	        List<EvalRunSnapshot> runs = new ArrayList<>();
66	        synchronized (lock) {
67	            for (String line : readLines()) {
68	                if (line == null || line.isBlank()) continue;
69	                try {
70	                    EvalRunSnapshot run = MAPPER.readValue(line, EvalRunSnapshot.class);
71	                    if (flavor == null || flavor.equals(run.flavor())) runs.add(run);
72	                } catch (Exception e) {
73	                    // skip a malformed line rather than failing the whole history
74	                }
75	            }
76	        }
77	        // File order is chronological (append-on-save); reverse for newest-first.
78	        Collections.reverse(runs);
79	        return runs;
80	    }
81	
82	    /** Removes the saved run(s) with the given {@code savedAt} id; returns how many were removed. */
83	    public int delete(String savedAt) throws IOException {
84	        if (savedAt == null || savedAt.isBlank()) return 0;
85	        synchronized (lock) {
86	            List<String> lines = readLines();
87	            List<String> kept = new ArrayList<>();
88	            int removed = 0;
89	            for (String line : lines) {
90	                if (matchesSavedAt(line, savedAt)) {
91	                    removed++;
92	                } else {
93	                    kept.add(line);
94	                }
95	            }
96	            if (removed > 0) {
97	                Path file = historyFile();
98	                Files.createDirectories(file.getParent());
99	                Files.write(file, kept);
100	            }
101	            return removed;
102	        }
103	    }
104	
105	    // A malformed line can't match (and is preserved), so a bad line never blocks deletion.
106	    private static boolean matchesSavedAt(String line, String savedAt) {
107	        if (line == null || line.isBlank()) return false;
108	        try {
109	            return savedAt.equals(MAPPER.readValue(line, EvalRunSnapshot.class).savedAt());
110	        } catch (Exception e) {
111	            return false;
112	        }
113	    }
114	
115	    private List<String> readLines() throws IOException {
116	        Path file = historyFile();
117	        return Files.exists(file) ? Files.readAllLines(file) : List.of();
118	    }
119	
120	    private static String blankTo(String value, String fallback) {
121	        return (value == null || value.isBlank()) ? fallback : value;
122	    }
123	
124	    private static EvalRunSnapshot snapshotOf(EvalReport report, String savedAt) {
125	        JudgeSummary judge = report.judge();
126	        boolean judged = judge != null && judge.ran();
127	        // Default the identity/label fields so a malformed body can't persist an unlistable snapshot.
128	        return new EvalRunSnapshot(
129	            savedAt,
130	            blankTo(report.flavor(), "unknown"),
131	            blankTo(report.modelLabel(), "unknown"),
132	            report.sessionCount(),
133	            report.evaluatedSessions(),
134	            report.avgScore(),
135	            report.checkPassRates() == null ? List.of() : report.checkPassRates(),
136	            judged,
137	            judged ? judge.judgedSessions() : 0,
138	            judged ? judge.avgFaithfulness() : 0.0,
139	            judged ? judge.avgActionability() : 0.0,
140	            judged ? judge.avgClarity() : 0.0
141	        );
142	    }
143	}
