18	import jakarta.inject.Inject;
19	import jakarta.inject.Singleton;
20	import java.util.Optional;
21	
22	/**
23	 * Central configuration for the AI backend. Two providers are supported:
24	 *
25	 * <ul>
26	 *   <li>{@code GEMINI} (default) — the remote Google Gemini API, requiring {@code GEMINI_API_KEY}.
27	 *   <li>{@code OLLAMA} — a local model (e.g. Gemma) served by Ollama; no API key required.
28	 * </ul>
29	 *
30	 * <p>Selection and settings come from environment variables:
31	 *
32	 * <ul>
33	 *   <li>{@code AI_PROVIDER} — {@code gemini} (default) or {@code ollama}
34	 *   <li>{@code GEMINI_API_KEY}, {@code GEMINI_MODEL} (default {@code gemini-3.5-flash})
35	 *   <li>{@code OLLAMA_BASE_URL} (default {@code http://localhost:11434}),
36	 *       {@code OLLAMA_MODEL} (default {@code gemma4})
37	 * </ul>
38	 *
39	 * <p>Reading through this bean (rather than {@code System.getenv} inline) gives tests a seam: the
40	 * package-private constructor accepts explicit values without touching process environment.
41	 */
42	@Singleton
43	public class AiConfig {
44	
45	    public enum Provider {
46	        GEMINI,
47	        OLLAMA,
48	    }
49	
50	    static final String DEFAULT_GEMINI_MODEL = "gemini-3.5-flash";
51	    static final String DEFAULT_OLLAMA_BASE_URL = "http://localhost:11434";
52	    static final String DEFAULT_OLLAMA_MODEL = "gemma4";
53	
54	    private final String providerName;
55	    private final String geminiApiKey;
56	    private final String geminiModel;
57	    private final String ollamaBaseUrl;
58	    private final String ollamaModel;
59	
60	    @Inject
61	    public AiConfig() {
62	        this(
63	            env("AI_PROVIDER"),
64	            env("GEMINI_API_KEY"),
65	            envOr("GEMINI_MODEL", DEFAULT_GEMINI_MODEL),
66	            envOr("OLLAMA_BASE_URL", DEFAULT_OLLAMA_BASE_URL),
67	            envOr("OLLAMA_MODEL", DEFAULT_OLLAMA_MODEL)
68	        );
69	    }
70	
71	    // Test seam: construct with explicit values, bypassing the environment.
72	    AiConfig(
73	        String providerName,
74	        String geminiApiKey,
75	        String geminiModel,
76	        String ollamaBaseUrl,
77	        String ollamaModel
78	    ) {
79	        this.providerName = providerName;
80	        this.geminiApiKey = geminiApiKey;
81	        this.geminiModel = blankTo(geminiModel, DEFAULT_GEMINI_MODEL);
82	        this.ollamaBaseUrl = blankTo(ollamaBaseUrl, DEFAULT_OLLAMA_BASE_URL);
83	        this.ollamaModel = blankTo(ollamaModel, DEFAULT_OLLAMA_MODEL);
84	    }
85	
86	    public Provider provider() {
87	        return providerName != null && providerName.trim().equalsIgnoreCase("ollama")
88	            ? Provider.OLLAMA
89	            : Provider.GEMINI;
90	    }
91	
92	    public Optional<String> geminiApiKey() {
93	        return (geminiApiKey == null || geminiApiKey.isBlank())
94	            ? Optional.empty()
95	            : Optional.of(geminiApiKey);
96	    }
97	
98	    public String geminiModel() {
99	        return geminiModel;
100	    }
101	
102	    public String ollamaBaseUrl() {
103	        return ollamaBaseUrl;
104	    }
105	
106	    public String ollamaModel() {
107	        return ollamaModel;
108	    }
109	
110	    /**
111	     * @return whether the selected provider has everything it needs to run. Ollama needs no key;
112	     *     Gemini requires {@code GEMINI_API_KEY}.
113	     */
114	    public boolean isConfigured() {
115	        return provider() == Provider.OLLAMA || geminiApiKey().isPresent();
116	    }
117	
118	    /**
119	     * @return a user-facing message explaining why analysis cannot run when {@link #isConfigured()}
120	     *     is false.
121	     */
122	    public String notConfiguredMessage() {
123	        return "Error: GEMINI_API_KEY environment variable is not set. Cannot use LangChain4j analysis.";
124	    }
125	
126	    /**
127	     * A real environment variable, else the {@code .env} file, else empty. A variable that is *set but
128	     * blank* wins too (it deliberately blanks the value), matching the precedence in {@code Application}.
129	     */
130	    private static String env(String key) {
131	        String value = System.getenv(key);
132	        if (value == null) value = DotEnv.get(key);
133	        return value == null ? "" : value;
134	    }
135	
136	    private static String envOr(String key, String fallback) {
137	        String value = env(key);
138	        return value.isBlank() ? fallback : value;
139	    }
140	
141	    private static String blankTo(String value, String fallback) {
142	        return (value == null || value.isBlank()) ? fallback : value;
143	    }
144	}
