16	package io.github.glaforge.agybrainviz;
17	
18	import jakarta.inject.Singleton;
19	import java.io.IOException;
20	import java.nio.file.Files;
21	import java.nio.file.Path;
22	import java.nio.file.Paths;
23	import java.util.HashMap;
24	import java.util.List;
25	import java.util.Map;
26	import java.util.Optional;
27	import java.util.stream.Stream;
28	
29	/**
30	 * Reads Claude Code sessions from {@code ~/.claude/projects/<dir>/<uuid>.jsonl} and exposes them
31	 * through {@link SessionSource}, so the existing frontend and analysis pipeline can render and
32	 * summarize them. Rollout lines are converted by {@link ClaudeCodeAdapter}.
33	 */
34	@Singleton
35	public class ClaudeCodeSessionReader implements SessionSource {
36	
37	    /** The flavor selector value the frontend sends for Claude Code sessions. */
38	    public static final String FLAVOR = "claude-code";
39	
40	    private static final int SUMMARY_SCAN_LINES = 256;
41	
42	    @Override
43	    public boolean handles(String flavor) {
44	        return FLAVOR.equals(flavor);
45	    }
46	
47	    private Path projectsDir() {
48	        return Paths.get(System.getProperty("user.home"), ".claude", "projects");
49	    }
50	
51	    @Override
52	    public List<Map<String, String>> listConversations() {
53	        Path root = projectsDir();
54	        if (!Files.isDirectory(root)) return List.of();
55	
56	        try (Stream<Path> paths = Files.walk(root)) {
57	            return paths
58	                .filter(p -> p.getFileName().toString().endsWith(".jsonl"))
59	                .filter(Files::isRegularFile)
60	                .map(this::describe)
61	                .filter(info -> info != null)
62	                .sorted((a, b) ->
63	                    Long.compare(
64	                        Long.parseLong(b.get("updatedAt")),
65	                        Long.parseLong(a.get("updatedAt"))
66	                    )
67	                )
68	                .toList();
69	        } catch (IOException e) {
70	            e.printStackTrace();
71	            return List.of();
72	        }
73	    }
74	
75	    private Map<String, String> describe(Path file) {
76	        try {
77	            String id = stripExtension(file.getFileName().toString());
78	            List<String> head;
79	            try (Stream<String> lines = Files.lines(file)) {
80	                head = lines.limit(SUMMARY_SCAN_LINES).toList();
81	            }
82	            String summary = ClaudeCodeAdapter
83	                .deriveSummary(head)
84	                .orElse("Claude Code session " + id.substring(0, Math.min(8, id.length())));
85	            long modified = Files.getLastModifiedTime(file).toMillis();
86	
87	            Map<String, String> info = new HashMap<>();
88	            info.put("id", id);
89	            info.put("summary", summary);
90	            info.put("updatedAt", String.valueOf(modified));
91	            return info;
92	        } catch (IOException e) {
93	            return null;
94	        }
95	    }
96	
97	    @Override
98	    public String transcriptJson(String id) throws IOException {
99	        Path file = findById(id);
100	        if (file == null) return "[]";
101	        return ClaudeCodeAdapter.toTranscriptJson(Files.readAllLines(file));
102	    }
103	
104	    @Override
105	    public boolean sessionExists(String id) throws IOException {
106	        return findById(id) != null;
107	    }
108	
109	    @Override
110	    public List<List<String>> analysisSequences(String id) throws IOException {
111	        Path file = findById(id);
112	        if (file == null) return List.of();
113	        return ClaudeCodeAdapter.toAnalysisSequences(Files.readAllLines(file));
114	    }
115	
116	    // Summaries are cached in a tool-owned hidden directory under ~/.claude/projects so we never
117	    // write alongside the files Claude Code itself manages.
118	    private SummaryCache cache() {
119	        return new SummaryCache(projectsDir().resolve(".agybrainviz"));
120	    }
121	
122	    @Override
123	    public Optional<String> cachedSummary(String id) throws IOException {
124	        return cache().read(id);
125	    }
126	
127	    @Override
128	    public void deleteCache(String id) throws IOException {
129	        cache().delete(id);
130	    }
131	
132	    @Override
133	    public void writeCache(String id, String summaryJson, String title) throws IOException {
134	        cache().write(id, summaryJson, title);
135	    }
136	
137	    // Locate a session by matching its id against actual filenames (never build a path from the id,
138	    // which would allow traversal).
139	    private Path findById(String id) throws IOException {
140	        Path root = projectsDir();
141	        if (!Files.isDirectory(root)) return null;
142	        try (Stream<Path> paths = Files.walk(root)) {
143	            return paths
144	                .filter(Files::isRegularFile)
145	                .filter(p -> p.getFileName().toString().endsWith(".jsonl"))
146	                .filter(p -> stripExtension(p.getFileName().toString()).equals(id))
147	                .findFirst()
148	                .orElse(null);
149	        }
150	    }
151	
152	    private static String stripExtension(String name) {
153	        int dot = name.lastIndexOf('.');
154	        return dot > 0 ? name.substring(0, dot) : name;
155	    }
156	}
