16	package io.github.glaforge.agybrainviz;
17	
18	import com.fasterxml.jackson.databind.ObjectMapper;
19	import io.micronaut.http.annotation.Controller;
20	import io.micronaut.http.annotation.Get;
21	import io.micronaut.http.annotation.PathVariable;
22	import io.micronaut.http.annotation.QueryValue;
23	import io.micronaut.scheduling.TaskExecutors;
24	import io.micronaut.scheduling.annotation.ExecuteOn;
25	import io.micronaut.serde.annotation.Serdeable;
26	import jakarta.inject.Inject;
27	import jakarta.inject.Named;
28	import java.io.IOException;
29	import java.nio.file.Files;
30	import java.nio.file.Path;
31	import java.util.ArrayList;
32	import java.util.List;
33	import java.util.Map;
34	import java.util.Optional;
35	import java.util.concurrent.ConcurrentHashMap;
36	import java.util.concurrent.ExecutorService;
37	import java.util.concurrent.Future;
38	import java.util.concurrent.Semaphore;
39	import java.util.concurrent.atomic.AtomicBoolean;
40	import java.util.concurrent.atomic.AtomicInteger;
41	import java.util.function.ToIntFunction;
42	
43	@Controller("/api/analysis")
44	public class AnalysisController {
45	
46	    private static final int MAX_TOKENS_PER_CHUNK = 100_000;
47	    private static final Map<String, ProgressState> progressMap = new ConcurrentHashMap<>();
48	
49	    @Serdeable
50	    public record ProgressState(int progress, String phase) {}
51	
52	    @Get(value = "/conversations/{id}/progress", produces = "application/json")
53	    public ProgressResponse getProgress(@PathVariable String id) {
54	        ProgressState state = progressMap.get(id);
55	        if (state == null) {
56	            return new ProgressResponse("", -1);
57	        }
58	        return new ProgressResponse(state.phase(), state.progress());
59	    }
60	
61	    @Serdeable
62	    public record ProgressResponse(String phase, int progress) {}
63	
64	    private final AnalyzerService analyzerService;
65	    private final ExecutorService executor;
66	    private final AiConfig aiConfig;
67	    private final TokenCounter tokenCounter;
68	    private final List<SessionSource> sessionSources;
69	
70	    @Inject
71	    public AnalysisController(
72	        AnalyzerService analyzerService,
73	        @Named(TaskExecutors.IO) ExecutorService executor,
74	        AiConfig aiConfig,
75	        TokenCounter tokenCounter,
76	        List<SessionSource> sessionSources
77	    ) {
78	        this.analyzerService = analyzerService;
79	        this.executor = executor;
80	        this.aiConfig = aiConfig;
81	        this.tokenCounter = tokenCounter;
82	        this.sessionSources = sessionSources;
83	    }
84	
85	    private Optional<SessionSource> sourceFor(String flavor) {
86	        return sessionSources.stream().filter(s -> s.handles(flavor)).findFirst();
87	    }
88	
89	    private static final Map<String, Object> runningTasks = new ConcurrentHashMap<>();
90	
91	    @ExecuteOn(TaskExecutors.IO)
92	    @Get(value = "/conversations/{id}/summarize", produces = "application/json")
93	    public String summarizeConversation(
94	        @PathVariable String id,
95	        @QueryValue Optional<Boolean> force,
96	        @QueryValue Optional<String> flavor
97	    ) throws IOException {
98	        if (!aiConfig.isConfigured()) {
99	            // Serialize via Jackson so the message is always valid JSON, regardless of its content.
100	            return new ObjectMapper()
101	                .writeValueAsString(Map.of("summary", aiConfig.notConfiguredMessage()));
102	        }
103	
104	        if (runningTasks.putIfAbsent(id, new Object()) != null) {
105	            return "{\"summary\": \"Analysis is already running in the background for this conversation. Please wait a moment and refresh.\"}";
106	        }
107	
108	        try {
109	            Optional<SessionSource> source = sourceFor(flavor.orElse(""));
110	            boolean external = source.isPresent();
111	            boolean forceRecompute = force.orElse(false);
112	
113	            // Antigravity caches the summary inside the agent's own brain dir; external sources
114	            // (Codex, Claude Code) cache via their SessionSource. Antigravity paths are resolved up
115	            // front; for external sources they stay null.
116	            Path logsDir = external
117	                ? null
118	                : AntigravityPaths.logsDir(flavor.orElse(AntigravityPaths.DEFAULT_FLAVOR), id);
119	            Path transcriptPath = external ? null : AntigravityPaths.transcript(logsDir);
120	            Path summaryJsonPath = external ? null : AntigravityPaths.summaryJson(logsDir);
121	            Path shortTitlePath = external ? null : AntigravityPaths.shortTitle(logsDir);
122	
123	            boolean exists = external
124	                ? source.get().sessionExists(id)
125	                : Files.exists(transcriptPath);
126	            if (!exists) {
127	                return "{\"summary\": \"No transcript found.\"}";
128	            }
129	
130	            if (!forceRecompute) {
131	                Optional<String> cached = external
132	                    ? source.get().cachedSummary(id)
133	                    : (
134	                        Files.exists(summaryJsonPath)
135	                            ? Optional.of(Files.readString(summaryJsonPath))
136	                            : Optional.empty()
137	                    );
138	                if (cached.isPresent()) {
139	                    return cached.get();
140	                }
141	            } else if (external) {
142	                source.get().deleteCache(id);
143	            } else {
144	                Files.deleteIfExists(summaryJsonPath);
145	            }
146	
147	            ObjectMapper mapper = new ObjectMapper();
148	            AnalysisResponse responseObj = null;
149	            boolean consolidationFellBack = false;
150	
151	            try {
152	                List<List<String>> sequences = external
153	                    ? source.get().analysisSequences(id)
154	                    : TranscriptParser.parseSequences(Files.readAllLines(transcriptPath));
155	
156	                ToIntFunction<String> tokenFn = tokenCounter::estimate;
157	
158	                progressMap.put(id, new ProgressState(5, "Estimating Tokens & Chunking...")); // Phase 1: Estimating
159	
160	                List<String> combinedLines = new ArrayList<>();
161	                for (List<String> seq : sequences) {
162	                    combinedLines.addAll(seq);
163	                }
164	                List<List<String>> optimalChunks = new ArrayList<>();
165	                TranscriptParser.splitIntoSafeChunks(
166	                    combinedLines,
167	                    tokenFn,
168	                    MAX_TOKENS_PER_CHUNK,
169	                    optimalChunks
170	                );
171	
172	                System.out.println(
173	                    "Total optimal chunks to process in parallel: " + optimalChunks.size()
174	                );
175	
176	                progressMap.put(id, new ProgressState(0, "Starting chunk processing...")); // start at 0%
177	
178	                List<Future<AnalysisResponse>> futures = new ArrayList<>();
179	                AtomicInteger completed = new AtomicInteger(0);
180	
181	                // Limit to 20 concurrent LLM requests, as we have drastically reduced chunk count
182	                Semaphore rateLimitSemaphore = new Semaphore(20);
183	
184	                for (List<String> chunkLines : optimalChunks) {
185	                    futures.add(
186	                        executor.submit(() -> {
187	                            try {
188	                                rateLimitSemaphore.acquire();
189	                            } catch (InterruptedException e) {
190	                                Thread.currentThread().interrupt();
191	                                return null;
192	                            }
193	
194	                            try {
195	                                String chunk = String.join("\n", chunkLines);
196	                                AnalysisResponse seqResponse = null;
197	                                try {
198	                                    seqResponse = analyzerService.analyze(chunk);
199	                                } catch (Exception e) {
200	                                    System.err.println(
201	                                        "Failed to parse chunk from LLM: " + e.getMessage()
202	                                    );
203	                                    e.printStackTrace();
204	                                    // Ignore unparseable chunk
205	                                }
206	
207	                                int comp = completed.incrementAndGet();
208	                                // Scale parallel processing to 90% of the total progress
209	                                int pct = (int) Math.round((comp * 90.0) / optimalChunks.size());
210	                                String phaseMsg =
211	                                    "Processing chunk " +
212	                                    comp +
213	                                    " of " +
214	                                    optimalChunks.size() +
215	                                    "...";
216	
217	                                // Prevent progress moving backwards if futures finish out of order
218	                                progressMap.compute(
219	                                    id,
220	                                    (k, v) -> {
221	                                        if (v == null || pct > v.progress()) {
222	                                            return new ProgressState(pct, phaseMsg);
223	                                        }
224	                                        return v;
225	                                    }
226	                                );
227	
228	                                return seqResponse;
229	                            } finally {
230	                                rateLimitSemaphore.release();
231	                            }
232	                        })
233	                    );
234	                }
235	
236	                List<AnalysisResponse> seqResponses = new ArrayList<>();
237	                for (Future<AnalysisResponse> f : futures) {
238	                    AnalysisResponse r = f.get();
239	                    if (r != null) seqResponses.add(r);
240	                }
241	
242	                if (seqResponses.isEmpty()) {
243	                    // Distinguish "nothing to analyze" from "the model failed for every chunk".
244	                    String msg = optimalChunks.isEmpty()
245	                        ? "No transcript lines found."
246	                        : "Analysis could not be generated: the model did not return a result for any part of this conversation. Please try again.";
247	                    return mapper.writeValueAsString(Map.of("summary", msg));
248	                } else if (seqResponses.size() == 1) {
249	                    responseObj = seqResponses.get(0);
250	                } else {
251	                    progressMap.put(id, new ProgressState(90, "Consolidating final analysis..."));
252	
253	                    // Keep the progress bar moving smoothly during the long final LLM consolidation
254	                    AtomicBoolean consolidationDone = new AtomicBoolean(false);
255	                    Future<?> fakeProgress = executor.submit(() -> {
256	                        int p = 90;
257	                        while (!consolidationDone.get() && p < 99) {
258	                            try {
259	                                Thread.sleep(2000);
260	                            } catch (InterruptedException e) {
261	                                break;
262	                            }
263	                            if (!consolidationDone.get()) {
264	                                int nextP = p + 1;
265	                                progressMap.put(
266	                                    id,
267	                                    new ProgressState(nextP, "Consolidating final analysis...")
268	                                );
269	                                p = nextP;
270	                            }
271	                        }
272	                    });
273	
274	                    try {
275	                        responseObj =
276	                            recursivelyConsolidate(seqResponses, tokenFn, mapper, 500_000);
277	                    } catch (Exception e) {
278	                        // LLM consolidation failed (e.g. API timeout). Rather than discard all the
279	                        // per-chunk work, merge the partial analyses locally so the user still gets
280	                        // a usable summary.
281	                        System.err.println(
282	                            "Consolidation failed; using local merge fallback: " + e.getMessage()
283	                        );
284	                        responseObj = localMerge(seqResponses);
285	                        consolidationFellBack = true;
286	                    } finally {
287	                        consolidationDone.set(true);
288	                        fakeProgress.cancel(true);
289	                    }
290	                }
291	
292	                progressMap.put(id, new ProgressState(100, "Done"));
293	
294	                String jsonResponse = mapper.writeValueAsString(responseObj);
295	
296	                // Don't persist a degraded local-merge fallback: the consolidation failure was
297	                // likely transient, so a later (non-forced) load should retry the LLM rather than
298	                // serve the cruder summary.
299	                if (consolidationFellBack) {
300	                    return jsonResponse;
301	                }
302	
303	                String title = responseObj.shortTitle();
304	                try {
305	                    if (external) {
306	                        source.get().writeCache(id, jsonResponse, title);
307	                    } else {
308	                        // The short title is best-effort; a failure here must not block caching or
309	                        // returning the summary.
310	                        try {
311	                            if (title != null && !title.isEmpty()) {
312	                                Files.writeString(shortTitlePath, title.trim());
313	                            }
314	                        } catch (Exception ignore) {}
315	                        Files.writeString(summaryJsonPath, jsonResponse);
316	                    }
317	                    return jsonResponse;
318	                } catch (Exception e) {
319	                    throw new Exception("Invalid JSON response");
320	                }
321	            } catch (Exception e) {
322	                System.err.println("Exception caught during analysis:");
323	                e.printStackTrace();
324	                try {
325	                    return mapper.writeValueAsString(
326	                        Map.of("summary", "Error generating summary: " + e.getMessage())
327	                    );
328	                } catch (Exception ex) {
329	                    return "{\"summary\": \"Error generating summary: Unknown error\"}";
330	                }
331	            } finally {
332	                progressMap.remove(id);
333	            }
334	        } finally {
335	            runningTasks.remove(id);
336	        }
337	    }
338	
339	    private AnalysisResponse recursivelyConsolidate(
340	        List<AnalysisResponse> responses,
341	        ToIntFunction<String> tokenFn,
342	        ObjectMapper mapper,
343	        int maxTokens
344	    ) throws Exception {
345	        String json = mapper.writeValueAsString(responses);
346	        boolean withinBudget;
347	        try {
348	            withinBudget = tokenFn.applyAsInt(json) <= maxTokens;
349	        } catch (Exception e) {
350	            // Only token estimation is best-effort here; fall back to a char-length heuristic so a
351	            // failed estimate doesn't get mistaken for a failed consolidation.
352	            withinBudget = (json.length() / 4) <= maxTokens;
353	        }
354	        // A consolidation failure below propagates to the caller (which falls back to a local merge).
355	        if (withinBudget || responses.size() <= 1) {
356	            return analyzerService.consolidateAnalysis(json);
357	        }
358	
359	        int mid = responses.size() / 2;
360	        AnalysisResponse r1 = recursivelyConsolidate(
361	            responses.subList(0, mid),
362	            tokenFn,
363	            mapper,
364	            maxTokens
365	        );
366	        AnalysisResponse r2 = recursivelyConsolidate(
367	            responses.subList(mid, responses.size()),
368	            tokenFn,
369	            mapper,
370	            maxTokens
371	        );
372	        return analyzerService.consolidateAnalysis(mapper.writeValueAsString(List.of(r1, r2)));
373	    }
374	
375	    /**
376	     * Deterministically merges per-chunk analyses without calling the LLM. Used as a fallback when
377	     * LLM consolidation fails, so the user still gets a usable (if less polished) summary instead of
378	     * an error.
379	     */
380	    private AnalysisResponse localMerge(List<AnalysisResponse> responses) {
381	        String shortTitle = "Session analysis";
382	        StringBuilder summary = new StringBuilder();
383	        List<String> flow = new ArrayList<>();
384	        List<AgentAction> actions = new ArrayList<>();
385	        List<Issue> issues = new ArrayList<>();
386	        List<String> recommendations = new ArrayList<>();
387	
388	        for (AnalysisResponse r : responses) {
389	            if (r == null) continue;
390	            if (
391	                "Session analysis".equals(shortTitle) &&
392	                r.shortTitle() != null &&
393	                !r.shortTitle().isBlank()
394	            ) {
395	                shortTitle = r.shortTitle();
396	            }
397	            if (r.summary() != null && !r.summary().isBlank()) {
398	                if (summary.length() > 0) summary.append(" ");
399	                summary.append(r.summary().trim());
400	            }
401	            if (r.flow() != null) {
402	                for (String f : r.flow()) if (f != null && !flow.contains(f)) flow.add(f);
403	            }
404	            if (r.agentActions() != null) actions.addAll(r.agentActions());
405	            if (r.issues() != null) issues.addAll(r.issues());
406	            if (r.recommendations() != null) {
407	                for (String rec : r.recommendations()) {
408	                    if (rec != null && !recommendations.contains(rec)) recommendations.add(rec);
409	                }
410	            }
411	        }
412	
413	        String summaryText = summary.length() > 4000
414	            ? summary.substring(0, 4000) + "..."
415	            : summary.toString();
416	        summaryText =
417	            "(Combined from " +
418	            responses.size() +
419	            " partial analyses; full consolidation was unavailable.) " +
420	            summaryText;
421	
422	        return new AnalysisResponse(
423	            shortTitle,
424	            cap(flow, 40),
425	            cap(actions, 40),
426	            cap(issues, 40),
427	            cap(recommendations, 30),
428	            summaryText
429	        );
430	    }
431	
432	    private static <T> List<T> cap(List<T> list, int max) {
433	        return list.size() > max ? new ArrayList<>(list.subList(0, max)) : list;
434	    }
435	}
